import React, { useState, useEffect } from "react";
import { Link } from "react-scroll";
import '../styles/Header.css';

const headerItems = [
    {
        name: "Home",
        path: "home",
    },
    {
        name: "About",
        path: "about",
    },
    {
        name: "Work",
        path: "work",
    },
    {
        name: "Blog",
        path: "blog",
    },
    {
        name: "Contact",
        path: "contact",
    }
]

function Header(props) {
    const [color, setColor] = useState("none");
    useEffect(() => {
        window.addEventListener("scroll", (event) => {
            if (window.scrollY >= window.innerHeight - 22) {
                setColor("rgba(41, 52, 72, 0.5)");
            } else {
                setColor("none");
            }
        })
    }, [color])
    return (
        <div className="header" style={{
            background: color
        }}>
            {
                headerItems.map((item, index) =>
                    <Link
                        key={index}
                        to={item.path}
                        style={{
                            borderBottom: props.active === item.path ? "solid 1.5px var(--red)" : ""
                        }}
                        className="headerLink"
                        spy={true}
                        smooth={true}
                        duration={300}
                    >
                        {item.name}
                    </Link>
                )
            }
        </div>
    );
}

export default Header;
